code.C++:
#include <stdio.h>

int main() {
    int num, reversedNum = 0, remainder;
    scanf("%d", &num);

    while (num != 0) {
        remainder = num % 10;
        reversedNum = reversedNum * 10 + remainder;
        num /= 10;
    }

    printf("%d", reversedNum);

    return 0;
}

